from langchain_openai import ChatOpenAI
from langchain_core.tools import tool
from langgraph.prebuilt import create_react_agent

llm = ChatOpenAI(model="gpt-4o", temperature=0)

@tool
def search_web(query: str) -> str:
    """Search the web for current information."""
    # replace with a real search API call
    return f"Search results for '{query}': [result1, result2, ...]"

@tool
def run_python(code: str) -> str:
    """Execute a Python snippet and return stdout + stderr."""
    import subprocess, sys
    result = subprocess.run(
        [sys.executable, "-c", code],
        capture_output=True, text=True, timeout=10
    )
    return result.stdout + result.stderr

@tool
def read_file(path: str) -> str:
    """Read a file from the local filesystem."""
    with open(path) as f:
        return f.read()

agent = create_react_agent(model=llm, tools=[search_web, run_python, read_file])

# The agent decides which tools to call and in what order
result = agent.invoke({
    "messages": [("human", "Find the current Python version, run a quick hello-world, and tell me the result.")]
})
